var parseSuccess = false;
var healingNote = 'Nao foi possivel processar a resposta do Claude';
var fixedWorkflow = {};
var rawText = '';

var response = $input.first().json;
var prepNode = $('Prepare Claude Prompt').first().json;

var hasValidResponse = (
  response &&
  response.content &&
  Array.isArray(response.content) &&
  response.content.length > 0 &&
  response.content[0].text
);

if (!hasValidResponse) {
  healingNote = 'Claude API retornou resposta invalida. Verifique a chave ANTHROPIC_API_KEY.';
} else {
  rawText = response.content[0].text.trim();

  if (rawText.length === 0) {
    healingNote = 'Claude retornou texto em branco.';
  } else {
    var parsed = null;
    var parseError = '';
    try {
      parsed = JSON.parse(rawText);
    } catch(e1) {
      parseError = e1.message;
      var match = rawText.match(/\{[\s\S]*\}/);
      if (match) {
        try { parsed = JSON.parse(match[0]); } catch(e2) { parseError = e2.message; }
      }
    }

    if (parsed !== null && parsed !== undefined && typeof parsed === 'object' && !Array.isArray(parsed)) {
      fixedWorkflow = parsed;

      if (fixedWorkflow.healingNote) {
        healingNote = String(fixedWorkflow.healingNote);
        delete fixedWorkflow.healingNote;
      }

      var hasNodes = fixedWorkflow.nodes && Array.isArray(fixedWorkflow.nodes);
      var hasConnections = fixedWorkflow.connections && typeof fixedWorkflow.connections === 'object';

      if (!hasNodes || !hasConnections) {
        var missing = [];
        if (!hasNodes) missing.push('nodes');
        if (!hasConnections) missing.push('connections');
        if (!healingNote || healingNote === 'Nao foi possivel processar a resposta do Claude') {
          healingNote = 'JSON sem campos obrigatorios: ' + missing.join(', ');
        }
        fixedWorkflow = {};
      } else {
        parseSuccess = true;
        if (!healingNote || healingNote === 'Nao foi possivel processar a resposta do Claude') {
          healingNote = 'Fix gerado com sucesso pelo Claude';
        }
        if (!fixedWorkflow.name) {
          fixedWorkflow.name = prepNode.workflowName || 'Recovered Workflow';
        }
      }
    } else {
      healingNote = 'Claude nao retornou um objeto JSON valido. Erro: ' + parseError;
    }
  }
}

return [{
  json: {
    fixedWorkflow: fixedWorkflow,
    parseSuccess: parseSuccess,
    healingNote: healingNote,
    workflowId: prepNode.workflowId || '',
    workflowName: prepNode.workflowName || '',
    errorMessage: prepNode.errorMessage || '',
    errorNodeName: prepNode.errorNodeName || '',
    timestamp: prepNode.errorTimestamp || new Date().toISOString()
  }
}];

